package com.parkflow.mall.gateway;
import com.parkflow.mall.gateway.controller.ReservationGatewayController;import com.parkflow.mall.gateway.reservation.ReservationServiceProxy;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;import org.springframework.boot.test.mock.mockito.MockBean;import org.springframework.http.*;import org.springframework.test.web.servlet.MockMvc;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@WebMvcTest(ReservationGatewayController.class) class ReservationGatewayControllerTests { @Autowired MockMvc mvc; @MockBean ReservationServiceProxy proxy; @Test void reservationRoutesForwardAndInternalConsumeIsNotExposed()throws Exception{when(proxy.forward(anyString(),any(),any(),any())).thenReturn(ResponseEntity.ok("{}"));when(proxy.listPath(any(),any())).thenReturn("/api/reservations?status=RESERVED&vehiclePlate=59A1");mvc.perform(post("/api/reservations").contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isOk());verify(proxy).forward("/api/reservations",HttpMethod.POST,"{}",null);mvc.perform(get("/api/reservations/RSV-1")).andExpect(status().isOk());verify(proxy).forward("/api/reservations/RSV-1",HttpMethod.GET,null,null);mvc.perform(post("/api/reservations/RSV-1/cancel").contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isOk());mvc.perform(get("/api/reservations").param("status","RESERVED").param("vehiclePlate","59A1").header("Authorization","Bearer staff")).andExpect(status().isOk());verify(proxy).forward("/api/reservations?status=RESERVED&vehiclePlate=59A1",HttpMethod.GET,null,"Bearer staff");mvc.perform(post("/api/reservations/expire").header("Authorization","Bearer staff")).andExpect(status().isOk());verify(proxy).forward("/api/reservations/expire",HttpMethod.POST,null,"Bearer staff");mvc.perform(post("/internal/reservations/RSV-1/consume").content("{}")).andExpect(status().isNotFound());}}
